import { useState } from 'react';
import axios from 'axios';

const Summary = ({ docId }) => {
  const [summary, setSummary] = useState('');

  const handleSummarize = async () => {
    const token = localStorage.getItem('token');
    const res = await axios.get(`http://localhost:5000/api/documents/${docId}/summarize`, { headers: { Authorization: `Bearer ${token}` } });
    setSummary(res.data.summary);
  };

  return (
    <div className="mt-4">
      <button onClick={handleSummarize} className="bg-green-600 text-white p-2">Generate Summary</button>
      {summary && <p className="mt-2">{summary}</p>}
    </div>
  );
};

export default Summary;
